        });
    });

    describe('Instruction step keyboard accessibility', () => {
        it('highlights step on Enter key press', () => {
            renderWithSettings(
                <RecipeCard recipe={mockRecipe} index={0} isStandalone />
            );

            const step = screen.getByText('Step 1');
