45	    // Memoize the JSON-LD schema to avoid regeneration on every render
46	    // Wrapped in try-catch to prevent malformed recipe data from crashing the component
47	    const schemaJson = useMemo(() => {
48	        try {
49	            const schema: Record<string, unknown> = {
50	                "@context": "https://schema.org",
51	                "@type": "Recipe",
52	                "name": recipe.title,
53	                "description": `A recipe for ${recipe.title}`,
54	                "recipeIngredient": recipe.ingredients.map(i => `${i.amount} ${i.item}`),
55	                "recipeInstructions": recipe.instructions.map(step => ({
56	                    "@type": "HowToStep",
57	                    "text": step
58	                }))
59	            };
60	            // Add cookTime if available (e.g., "30 min" -> "PT30M")
61	            if (recipe.time) {
62	                const minutes = recipe.time.match(/(\d+)/)?.[1];
63	                if (minutes) {
64	                    schema.cookTime = `PT${minutes}M`;
65	                }
66	            }
67	            // Add nutrition info if available
68	            if (recipe.nutrition) {
69	                schema.nutrition = {
70	                    "@type": "NutritionInformation",
71	                    "calories": `${recipe.nutrition.calories} calories`,
72	                    "carbohydrateContent": `${recipe.nutrition.carbs} g`,
73	                    "fatContent": `${recipe.nutrition.fat} g`,
74	                    "proteinContent": `${recipe.nutrition.protein} g`
75	                };
76	            }
