78	            return JSON.stringify(schema).replace(/<\/script>/gi, '<\\/script>');
79	        } catch (error) {
80	            // Log error for debugging but return null to prevent crash
81	            console.error('Failed to generate JSON-LD schema for recipe:', recipe.title, error);
82	            return null;
83	        }
84	    }, [recipe]);
85	
86	
